import { BOX_SIZE, SUDOKU_SIZE } from '@sudoku/constants';
import { decodeSencode, encodeSudoku } from '@sudoku/sencode';
import { generateSudoku, solveSudoku } from '@sudoku/sudoku';
import { derived } from 'svelte/store';
import { hints } from './hints';
import { gameStore } from './domain';

// grid 暴露原始题面给定值（0 表示需要玩家填写的空位）。
// 它派生自 gameStore，因此 UI 会始终反映领域层状态。
const _puzzleStore = derived(gameStore, $gs => $gs.puzzle);
const _gridStore = derived(gameStore, $gs => $gs.grid);

export const grid = {
	subscribe: _puzzleStore.subscribe,

	generate(difficulty) {
		gameStore.start(generateSudoku(difficulty));
	},

	decodeSencode(sencode) {
		gameStore.start(decodeSencode(sencode));
	},

	get(gridStore, x, y) {
		return gridStore[y][x];
	},

	getSencode(gridStore) {
		return encodeSudoku(gridStore);
	},
};

// userGrid 暴露当前棋盘状态（题面给定值 + 玩家操作）。
// 所有变更都经由 gameStore，以便 Game 跟踪每一次状态变化。
export const userGrid = {
	subscribe: _gridStore.subscribe,

	set(pos, value) {
		gameStore.guess({ row: pos.y, col: pos.x, value });
	},

	applyHint(pos) {
		// 同步读取当前棋盘，以提供给求解器
		let currentGrid;
		const unsub = _gridStore.subscribe($g => { currentGrid = $g; });
		unsub();
		const solved = solveSudoku(currentGrid);
		hints.useHint();
		gameStore.guess({ row: pos.y, col: pos.x, value: solved[pos.y][pos.x] });
	},
};

export const invalidCells = derived(_gridStore, $userGrid => {
	const _invalidCells = [];

	const addInvalid = (x, y) => {
		const xy = x + ',' + y;
		if (!_invalidCells.includes(xy)) _invalidCells.push(xy);
	};

	for (let y = 0; y < SUDOKU_SIZE; y++) {
		for (let x = 0; x < SUDOKU_SIZE; x++) {

			const value = $userGrid[y][x];

			if (value) {
				for (let i = 0; i < SUDOKU_SIZE; i++) {
					// Check the row
					if (i !== x && $userGrid[y][i] === value) {
						addInvalid(x, y);
					}

					// Check the column
					if (i !== y && $userGrid[i][x] === value) {
						addInvalid(x, i);
					}
				}

				// Check the box
				const startY = Math.floor(y / BOX_SIZE) * BOX_SIZE;
				const endY = startY + BOX_SIZE;
				const startX = Math.floor(x / BOX_SIZE) * BOX_SIZE;
				const endX = startX + BOX_SIZE;
				for (let row = startY; row < endY; row++) {
					for (let col = startX; col < endX; col++) {
						if (row !== y && col !== x && $userGrid[row][col] === value) {
							addInvalid(col, row);
						}
					}
				}
			}

		}
	}

	return _invalidCells;
}, []);